import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.esapi.ESAPI;

public class XSSFixedCode {
    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Properly encode user input to prevent XSS
        String encodedUserInput = ESAPI.encoder().encodeForHTML(userInput);
        String output = "<p>" + encodedUserInput + "</p>";

        try {
            PrintWriter writer = new PrintWriter("output.html", "UTF-8");
            writer.println(output);
            writer.close();
            System.out.println("Output HTML file generated successfully.");
        } catch (IOException e) {
            System.out.println("Error writing output file: " + e.getMessage());
        }
    }
}

